import React from 'react';
import './FlipCard.css';


const FlipCard = ({ 
  image,           // фото для лицевой стороны
  backImage,       // новое фото для обратной стороны
  title, 
  buttonText = "Купить", 
  onButtonClick 
}) => {
  return (
    <div className="card">
      <div className="card-inner">
        <div className="card-front">
          <img src={image} alt={title} />
          <h2>{title}</h2>
        </div>
        <div className="card-back">
          <img src={backImage || image} alt={title} />
          <h2>{title}</h2>
          <BlobButton 
            type="primary"
            onClick={onButtonClick}
          >
            {buttonText}
          </BlobButton>
        </div>
      </div>
    </div>
  );
};

export default FlipCard;
